{
    void CheckFlag()
    {
        // In .NET 9, GetEnvironmentVariable returns null for empty vars on Linux.
        // Use GetEnvironmentVariables() to distinguish "not set" from "explicitly empty".
        var envVars = Environment.GetEnvironmentVariables();
        if (!envVars.Contains("MY_FLAG"))
